// --- Session Panel ---
const SessionPanel = () => {
  const { dataManager: dm, session } = useDataManager();
  const [userId, setUserId] = useState('');

  const handleLogin = async () => {
    const id = userId.trim() || 'user_' + generateId();
    await dm.setUserToken('tok_' + generateId());
    await dm.setRefreshToken('ref_' + generateId());
    await dm.setUserProfile({
      id,
      name: 'Demo User',
      email: `${id}@example.com`,
      avatar: null,
    });
    await dm.startSession(id);
    setUserId('');
    Alert.alert('Success', `Logged in as ${id}`);
  };

  const handleLogout = async () => {
    await dm.endSession();
    await dm.clearTokens();
    await dm.clearUserProfile();
    Alert.alert('Success', 'Logged out successfully');
  };

  const handleRefreshActivity = async () => {
    await dm.updateLastActivity();
    Alert.alert('Activity Updated', `Last activity: ${new Date().toLocaleTimeString()}`);
  };

  return (
    <View style={styles.panel}>
      <Text style={styles.panelTitle}>Session Management</Text>

      <View style={styles.statusRow}>
        <View style={[styles.statusDot, { backgroundColor: session.isLoggedIn ? '#4CAF50' : '#F44336' }]} />
        <Text style={styles.statusText}>
          {session.isLoggedIn ? 'Active Session' : 'No Active Session'}
        </Text>
      </View>

      {session.isLoggedIn ? (
        <View>
          <Text style={styles.infoText}>Session ID: {session.sessionId}</Text>
          <Text style={styles.infoText}>User: {session.userId}</Text>
          <Text style={styles.infoText}>
            Login: {session.loginTimestamp ? new Date(session.loginTimestamp).toLocaleString() : 'N/A'}
          </Text>
          <Text style={styles.infoText}>
            Last Activity: {session.lastActivity ? new Date(session.lastActivity).toLocaleString() : 'N/A'}
          </Text>
          <Text style={styles.infoText}>
            Valid: {dm.isSessionValid() ? 'Yes' : 'Expired'}
          </Text>
          <Text style={styles.infoText}>
            Token Expired: {dm.isTokenExpired() ? 'Yes' : 'No'}
          </Text>

          <View style={styles.buttonRow}>
            <TouchableOpacity style={styles.buttonSecondary} onPress={handleRefreshActivity}>
              <Text style={styles.buttonSecondaryText}>Refresh Activity</Text>
            </TouchableOpacity>
            <TouchableOpacity style={styles.buttonDanger} onPress={handleLogout}>
              <Text style={styles.buttonDangerText}>Logout</Text>
            </TouchableOpacity>
          </View>
        </View>
      ) : (
        <View>
          <TextInput
            style={styles.input}
            placeholder="User ID (optional)"
            value={userId}
            onChangeText={setUserId}
            placeholderTextColor="#999"
          />
          <TouchableOpacity style={styles.buttonPrimary} onPress={handleLogin}>
            <Text style={styles.buttonPrimaryText}>Login</Text>
          </TouchableOpacity>
        </View>
      )}
    </View>
  );
};

// --- Profile Panel ---
const ProfilePanel = () => {
  const { dataManager: dm, profile } = useDataManager();
  const [editName, setEditName] = useState('');
  const [editEmail, setEditEmail] = useState('');

  useEffect(() => {
    if (profile) {
      setEditName(profile.name || '');
      setEditEmail(profile.email || '');
    }
  }, [profile]);

  const handleUpdate = async () => {
    if (!profile) {
      Alert.alert('Error', 'Please login first');
      return;
    }
    await dm.setUserProfile({
      name: editName,
      email: editEmail,
    });
    Alert.alert('Success', 'Profile updated');
  };

  if (!profile) {
    return (
      <View style={styles.panel}>
        <Text style={styles.panelTitle}>User Profile</Text>
        <Text style={styles.emptyText}>No profile data. Please login first.</Text>
      </View>
    );
  }

  return (
    <View style={styles.panel}>
      <Text style={styles.panelTitle}>User Profile</Text>

      <Text style={styles.label}>Name</Text>
      <TextInput
        style={styles.input}
        value={editName}
        onChangeText={setEditName}
        placeholder="Enter name"
        placeholderTextColor="#999"
      />

      <Text style={styles.label}>Email</Text>
      <TextInput
        style={styles.input}
        value={editEmail}
        onChangeText={setEditEmail}
        placeholder="Enter email"
        keyboardType="email-address"
        placeholderTextColor="#999"
      />

      <Text style={styles.infoText}>ID: {profile.id}</Text>
      {profile.updatedAt && (
        <Text style={styles.infoText}>
          Last Updated: {new Date(profile.updatedAt).toLocaleString()}
        </Text>
      )}

      <TouchableOpacity style={styles.buttonPrimary} onPress={handleUpdate}>
        <Text style={styles.buttonPrimaryText}>Update Profile</Text>
      </TouchableOpacity>
    </View>
  );
};

// --- Settings Panel ---
const SettingsPanel = () => {
  const { dataManager: dm, settings } = useDataManager();

  const handleToggle = async (key) => {
    await dm.updateSetting(key, !settings[key]);
  };

  const handleThemeChange = async () => {
    const newTheme = settings.theme === 'light' ? 'dark' : 'light';
    await dm.updateSetting('theme', newTheme);
  };

  const handleFontSize = async () => {
    const sizes = ['small', 'medium', 'large'];
    const currentIndex = sizes.indexOf(settings.fontSize);
    const nextIndex = (currentIndex + 1) % sizes.length;
    await dm.updateSetting('fontSize', sizes[nextIndex]);
  };

  const handleDataUsage = async () => {
    const options = ['wifi_only', 'cellular', 'always'];
    const currentIndex = options.indexOf(settings.dataUsage);
    const nextIndex = (currentIndex + 1) % options.length;
    await dm.updateSetting('dataUsage', options[nextIndex]);
  };

  const handleReset = async () => {
    await dm.resetSettings();
    Alert.alert('Success', 'Settings reset to defaults');
  };

  return (
    <View style={styles.panel}>
      <Text style={styles.panelTitle}>App Settings</Text>

      <View style={styles.settingRow}>
        <Text style={styles.settingLabel}>Notifications</Text>
        <Switch
          value={settings.notifications}
          onValueChange={() => handleToggle('notifications')}
          trackColor={{ false: '#ccc', true: '#81C784' }}
          thumbColor={settings.notifications ? '#4CAF50' : '#f4f3f4'}
        />
      </View>

      <View style={styles.settingRow}>
        <Text style={styles.settingLabel}>Auto Sync</Text>
        <Switch
          value={settings.autoSync}
          onValueChange={() => handleToggle('autoSync')}
          trackColor={{ false: '#ccc', true: '#81C784' }}
          thumbColor={settings.autoSync ? '#4CAF50' : '#f4f3f4'}
        />
      </View>

      <View style={styles.settingRow}>
        <Text style={styles.settingLabel}>Biometric Login</Text>
        <Switch
          value={settings.biometricEnabled}
          onValueChange={() => handleToggle('biometricEnabled')}
          trackColor={{ false: '#ccc', true: '#81C784' }}
          thumbColor={settings.biometricEnabled ? '#4CAF50' : '#f4f3f4'}
        />
      </View>

      <TouchableOpacity style={styles.settingRow} onPress={handleThemeChange}>
        <Text style={styles.settingLabel}>Theme</Text>
        <Text style={styles.settingValue}>{settings.theme}</Text>
      </TouchableOpacity>

      <TouchableOpacity style={styles.settingRow} onPress={handleFontSize}>
        <Text style={styles.settingLabel}>Font Size</Text>
        <Text style={styles.settingValue}>{settings.fontSize}</Text>
      </TouchableOpacity>

      <TouchableOpacity style={styles.settingRow} onPress={handleDataUsage}>
        <Text style={styles.settingLabel}>Data Usage</Text>
        <Text style={styles.settingValue}>{settings.dataUsage.replace('_', ' ')}</Text>
      </TouchableOpacity>

      <Text style={styles.infoText}>Language: {settings.language}</Text>
      <Text style={styles.infoText}>
        Cache Expiry: {(settings.cacheExpiry / 60000).toFixed(0)} min
      </Text>

      <TouchableOpacity style={styles.buttonSecondary} onPress={handleReset}>
        <Text style={styles.buttonSecondaryText}>Reset to Defaults</Text>
      </TouchableOpacity>
    </View>
  );
};

// --- Preferences Panel ---
const PreferencesPanel = () => {
  const { dataManager: dm, preferences } = useDataManager();
  const [searchTerm, setSearchTerm] = useState('');

  const categories = ['Technology', 'Sports', 'Music', 'Travel', 'Food', 'Science', 'Art'];

  const handleAddSearch = async () => {
    if (searchTerm.trim()) {
      await dm.addRecentSearch(searchTerm.trim());
      setSearchTerm('');
    }
  };

  const handleToggleCategory = async (cat) => {
    await dm.toggleFavoriteCategory(cat);
  };

  const handleDisplayMode = async () => {
    const modes = ['list', 'grid', 'compact'];
    const currentIndex = modes.indexOf(preferences.displayMode);
    const nextIndex = (currentIndex + 1) % modes.length;
    await dm.setUserPreferences({ displayMode: modes[nextIndex] });
  };

  const handleSortOrder = async () => {
    const orders = ['newest', 'oldest', 'popular', 'alphabetical'];
    const currentIndex = orders.indexOf(preferences.sortOrder);
    const nextIndex = (currentIndex + 1) % orders.length;
    await dm.setUserPreferences({ sortOrder: orders[nextIndex] });
  };

  return (
    <View style={styles.panel}>
      <Text style={styles.panelTitle}>User Preferences</Text>

      <Text style={styles.label}>Favorite Categories</Text>
      <View style={styles.tagContainer}>
        {categories.map((cat) => {
          const isFav = preferences.favoriteCategories?.includes(cat);
          return (
            <TouchableOpacity
              key={cat}
              style={[styles.tag, isFav && styles.tagActive]}
              onPress={() => handleToggleCategory(cat)}
            >
              <Text style={[styles.tagText, isFav && styles.tagTextActive]}>{cat}</Text>
            </TouchableOpacity>
          );
        })}
      </View>

      <TouchableOpacity style={styles.settingRow} onPress={handleDisplayMode}>
        <Text style={styles.settingLabel}>Display Mode</Text>
        <Text style={styles.settingValue}>{preferences.displayMode}</Text>
      </TouchableOpacity>

      <TouchableOpacity style={styles.settingRow} onPress={handleSortOrder}>
        <Text style={styles.settingLabel}>Sort Order</Text>
        <Text style={styles.settingValue}>{preferences.sortOrder}</Text>
      </TouchableOpacity>

      <Text style={styles.label}>Recent Searches</Text>
      <View style={styles.searchRow}>
        <TextInput
          style={[styles.input, { flex: 1, marginRight: 8, marginBottom: 0 }]}
          value={searchTerm}
          onChangeText={setSearchTerm}
          placeholder="Add search term"
          placeholderTextColor="#999"
          onSubmitEditing={handleAddSearch}
        />
        <TouchableOpacity style={styles.buttonSmall} onPress={handleAddSearch}>
          <Text style={styles.buttonSmallText}>Add</Text>
        </TouchableOpacity>
      </View>

      {preferences.recentSearches?.length > 0 && (
        <View style={styles.tagContainer}>
          {preferences.recentSearches.slice(0, 10).map((term, index) => (
            <View key={`${term}-${index}`} style={styles.searchTag}>
              <Text style={styles.searchTagText}>{term}</Text>
            </View>
          ))}
        </View>
      )}
    </View>
  );
};

// --- Offline Content Panel ---
const OfflineContentPanel = () => {
  const { dataManager: dm } = useDataManager();
  const [cachedItems, setCachedItems] = useState({});
  const [contentId, setContentId] = useState('');
  const [contentBody, setContentBody] = useState('');

  const refreshCache = useCallback(() => {
    setCachedItems(dm.getAllCachedContent());
  }, [dm]);

  useEffect(() => {
    refreshCache();
    const unsub = dm.subscribe(STORAGE_KEYS.OFFLINE_CONTENT, () => {
      refreshCache();
    });
    return unsub;
  }, [dm, refreshCache]);

  const handleAddContent = async () => {
    const id = contentId.trim() || 'content_' + generateId();
    const body = contentBody.trim() || `Sample content for ${id} created at ${new Date().toLocaleString()}`;
    await dm.cacheContent(id, {
      title: `Article: ${id}`,
      body,
      author: 'Demo Author',
    });
    setContentId('');
    setContentBody('');
    Alert.alert('Cached', `Content "${id}" saved offline`);
  };

  const handleRemove = async (id) => {
    await dm.removeCachedContent(id);
  };

  const handleClearExpired = async () => {
    const removed = await dm.clearExpiredCache();
    Alert.alert('Cleanup', `Removed ${removed} expired items`);
  };

  const handleClearAll = async () => {
    await dm.clearAllCache();
    Alert.alert('Cleared', 'All cached content removed');
  };

  const stats = dm.getCacheStats();
  const itemKeys = Object.keys(cachedItems);

  return (
    <View style={styles.panel}>
      <Text style={styles.panelTitle}>Offline Content Cache</Text>

      <View style={styles.statsRow}>
        <View style={styles.statBox}>
          <Text style={styles.statNumber}>{stats.offlineContentCount}</Text>
          <Text style={styles.statLabel}>Items</Text>
        </View>
        <View style={styles.statBox}>
          <Text style={styles.statNumber}>{stats.totalCacheSizeKB}</Text>
          <Text style={styles.statLabel}>KB Total</Text>
        </View>
        <View style={styles.statBox}>
          <Text style={styles.statNumber}>{stats.totalKeys}</Text>
          <Text style={styles.statLabel}>Keys</Text>
        </View>
      </View>

      <Text style={styles.label}>Add Content</Text>
      <TextInput
        style={styles.input}
        value={contentId}
        onChangeText={setContentId}
        placeholder="Content ID (optional)"
        placeholderTextColor="#999"
      />
      <TextInput
        style={[styles.input, { height: 60 }]}
        value={contentBody}
        onChangeText={setContentBody}
        placeholder="Content body (optional)"
        placeholderTextColor="#999"
        multiline
      />
      <TouchableOpacity style={styles.buttonPrimary} onPress={handleAddContent}>
        <Text style={styles.buttonPrimaryText}>Cache Content</Text>
      </TouchableOpacity>

      {itemKeys.length > 0 && (
        <View style={{ marginTop: 12 }}>
          <Text style={styles.label}>Cached Items ({itemKeys.length})</Text>
          {itemKeys.map((key) => {
            const item = cachedItems[key];
            return (
              <View key={key} style={styles.cacheItem}>
                <View style={{ flex: 1 }}>
                  <Text style={styles.cacheItemTitle}>{item.data?.title || key}</Text>
                  <Text style={styles.cacheItemMeta}>
                    Cached: {new Date(item.cachedAt).toLocaleString()} | Views: {item.accessCount}
                  </Text>
                </View>
                <TouchableOpacity onPress={() => handleRemove(key)}>
                  <Text style={styles.removeText}>✕</Text>
                </TouchableOpacity>
              </View>
            );
          })}
        </View>
      )}

      <View style={styles.buttonRow}>
        <TouchableOpacity style={styles.buttonSecondary} onPress={handleClearExpired}>
          <Text style={styles.buttonSecondaryText}>Clear Expired</Text>
        </TouchableOpacity>
        <TouchableOpacity style={styles.buttonDanger} onPress={handleClearAll}>
          <Text style={styles.buttonDangerText}>Clear All</Text>
        </TouchableOpacity>
      </View>
    </View>
  );
};

// --- Danger Zone Panel ---
const DangerZonePanel = () => {
  const { dataManager: dm } = useDataManager();

  const handleClearAll = () => {
    Alert.alert(
      'Clear All Data',
      'This will remove all cached data, tokens, profile, settings, and offline content. Are you sure?',
      [
        { text: 'Cancel', style: 'cancel' },
        {
          text: 'Clear Everything',
          style: 'destructive',
          onPress: async () => {
            await dm.clearAll();
            Alert.alert('Done', 'All local data has been cleared');
          },
        },
      ]
    );
  };

  return (
    <View style={[styles.panel, { borderColor: '#FFCDD2' }]}>
      <Text style={[styles.panelTitle, { color: '#D32F2F' }]}>Danger Zone</Text>
      <Text style={styles.infoText}>
        Clear all locally stored data including tokens, profile, settings, preferences, and cached content.
      </Text>
      <TouchableOpacity style={styles.buttonDanger} onPress={handleClearAll}>
        <Text style={styles.buttonDangerText}>Clear All Local Data</Text>
      </TouchableOpacity>
    </View>
  );
};

// ==================== Main App Screen ====================

const AppContent = () => {
  const { isReady } = useDataManager();

  if (!isReady) {
    return (
      <View style={styles.loadingContainer}>
        <ActivityIndicator size="large" color="#1976D2" />
        <Text style={styles.loadingText}>Initializing Local Data Manager...</Text>
      </View>
    );
  }

  return (
    <ScrollView style={styles.container} contentContainerStyle={styles.scrollContent}>
      <Text style={styles.header}>Local Data Manager</Text>
      <Text style={styles.subHeader}>
        Cache user data, preferences, and offline content for optimal performance.
      </Text>

      <SessionPanel />
      <ProfilePanel />
      <SettingsPanel />
      <PreferencesPanel />
      <OfflineContentPanel />
      <DangerZonePanel />

      <View style={{ height: 40 }} />
    </ScrollView>
  );
};

const App = () => {
  return (
    <DataManagerProvider>
      <AppContent />
    </DataManagerProvider>
  );
};

